class Node:
 def __init__(self, data):
 self.data = data
 self.left = None
 self.right = None

def create_node(data):
 return Node(data)

typedef struct Node {
 int data;
 struct Node* left;
 struct Node* right;
} Node;

Node* create_node(int data) {
 Node* new_node = malloc(sizeof(Node));
 new_node->data = data;
 new_node->left = NULL;
 new_node->right = NULL;
 return new_node;
}
